13550', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "e3dd81291c27", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0908", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00034', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '假設世界經濟體有A與B兩國，兩國擁有相同數量的勞動。A國1單位勞動可生產1部電腦或是 2支手機，而B國1單位的勞動可生產2部電腦或是4支手機，下列敘述何者錯誤？', '["兩國生產電腦的機會成本相等", "兩國進行國際貿易不會有利得", "兩國的生產可能線為平行直線", "A國的生產可能線在B國生產可能線的右上方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "e3dd81291c27", "answer_pdf_sha1": "ca77505538ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00035', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '有關供給與需求彈性，下列敘述何者錯誤？', '["對大部分財貨而言，其需求的自身價格彈性為負", "對大部分財貨而言，其供給的價格彈性為正", "對正常財而言，需求的所得彈性為正", "對互補品而言，需求的交叉價格彈性為正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "e3dd81291c27", "answer_pdf_sha1": "ca77505538ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00036', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '假設咖啡的供需法則成立，若消費者的所得減少，且咖啡為一正常財，則下列敘述何者正確？', '["咖啡的需求增加，均衡交易量減少，均衡價格降低", "咖啡的需求增加，均衡交易量增加，均衡價格上漲", "咖啡的需求減少，均衡交易量減少，均衡價格降低", "咖啡的需求減少，均衡交易量增加，均衡價格上漲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "e3dd81291c27", "answer_pdf_sha1": "ca77505538ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00037', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-d3ff7f6b', 'sub-promotion-d592fc58-03', NULL, 'single_choice', '當X財與Y財為完全替代品時，下列敘述何者錯誤？', '["二者的邊際替代率為固定", "二者的無異曲線為直線", "二者的效用函數呈一次齊次的特質", "不管價格為何，消費者僅消費一種財貨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "e3dd81291c27", "answer_pdf_sha1": "ca77505538ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL)
